class Solution {
    public int maxScore(int[] nums) {
        Arrays.sort(nums);
        int score = 0;
        for (int i = 0; i < nums.length / 2; i++) {
            score += (i + 1) * gcd(nums[i], nums[nums.length - i - 1]);
        }
        return score;
    }
    private int gcd(int a, int b) {
        if (b == 0) {
            return a;
        }
        return gcd(b, a % b);
    }
}
